# ABOUTME: Redis client for Celery task queue and caching
# ABOUTME: Provides async Redis connection and health checks

import logging
from typing import Any, Optional
from redis.asyncio import Redis, ConnectionPool
from app.core.config import settings

logger = logging.getLogger(__name__)


class AsyncRedisClient:
    """Async Redis client wrapper for task queue and caching."""

    def __init__(self):
        """Initialize Redis client."""
        self.client: Optional[Redis] = None
        self._connection_pool: Optional[ConnectionPool] = None

    async def connect(self) -> None:
        """Establish Redis connection."""
        try:
            if not self.client:
                self._connection_pool = ConnectionPool.from_url(
                    settings.REDIS_URL,
                    decode_responses=True,
                    max_connections=10,
                )
                self.client = Redis(connection_pool=self._connection_pool)
                await self.client.ping()
                logger.info("Redis connection established")
        except Exception as e:
            logger.error(f"Failed to connect to Redis: {e}")
            raise

    async def disconnect(self) -> None:
        """Close Redis connection."""
        if self.client:
            await self.client.close()
            logger.info("Redis connection closed")

    async def ping(self) -> bool:
        """Ping Redis server."""
        try:
            if not self.client:
                await self.connect()
            response = await self.client.ping()
            return response is not None
        except Exception as e:
            logger.error(f"Redis ping failed: {e}")
            return False

    async def info(self) -> dict[str, Any]:
        """Get Redis server info."""
        try:
            if not self.client:
                await self.connect()
            return await self.client.info()
        except Exception as e:
            logger.error(f"Failed to get Redis info: {e}")
            return {}

    async def set(self, key: str, value: Any, ex: Optional[int] = None) -> bool:
        """Set a value in Redis."""
        try:
            if not self.client:
                await self.connect()
            await self.client.set(key, value, ex=ex)
            return True
        except Exception as e:
            logger.error(f"Failed to set Redis key {key}: {e}")
            return False

    async def get(self, key: str) -> Optional[Any]:
        """Get a value from Redis."""
        try:
            if not self.client:
                await self.connect()
            return await self.client.get(key)
        except Exception as e:
            logger.error(f"Failed to get Redis key {key}: {e}")
            return None

    async def delete(self, key: str) -> bool:
        """Delete a key from Redis."""
        try:
            if not self.client:
                await self.connect()
            result = await self.client.delete(key)
            return result > 0
        except Exception as e:
            logger.error(f"Failed to delete Redis key {key}: {e}")
            return False


# Global Redis client instance
redis_client = AsyncRedisClient()

