    retry_kwargs = {"max_retries": 2}
    bind = True


@celery_app.task(bind=True, base=AgentTask)
def generate_prompts(self, content_id: str, content_text: str, model: str = "sonnet"):
    """Generate flashcard prompts from content."""
    task_logger = TaskConfig.get_task_logger("generate_prompts")
